import "sort"

// SuffixArray builds the suffix array of an integer array.
func SuffixArray(arr []int) []int {
	n := len(arr)
	if n == 0 {
		return []int{}
	}
	sa := make([]int, n)
	rank := make([]int, n)
	tmp := make([]int, n)
	for i := 0; i < n; i++ {
		sa[i] = i
		rank[i] = arr[i]
	}
	for k := 1; k < n; k *= 2 {
		r := make([]int, n)
		copy(r, rank)
		step := k
		sort.Slice(sa, func(i, j int) bool {
			a, b := sa[i], sa[j]
			if r[a] != r[b] {
				return r[a] < r[b]
			}
			ra, rb := -1, -1
			if a+step < n {
				ra = r[a+step]
			}
			if b+step < n {
				rb = r[b+step]
			}
			return ra < rb
		})
		tmp[sa[0]] = 0
		for i := 1; i < n; i++ {
			tmp[sa[i]] = tmp[sa[i-1]]
			p0, c0 := r[sa[i-1]], r[sa[i]]
			p1, c1 := -1, -1
			if sa[i-1]+step < n {
				p1 = r[sa[i-1]+step]
			}
			if sa[i]+step < n {
				c1 = r[sa[i]+step]
			}
			if p0 != c0 || p1 != c1 {
				tmp[sa[i]]++
			}
		}
		copy(rank, tmp)
		if rank[sa[n-1]] == n-1 {
			break
		}
	}
	return sa
}

import java.util.*;

public class SuffixArray {
    public static int[] suffixArray(int[] arr) {
        int n = arr.length;
        if (n == 0) return new int[0];
        Integer[] sa = new Integer[n];
        int[] rank = new int[n];
        int[] tmp = new int[n];
        for (int i = 0; i < n; i++) {
            sa[i] = i;
            rank[i] = arr[i];
        }
        for (int k = 1; k < n; k *= 2) {
            final int[] r = rank;
            final int step = k;
            Arrays.sort(sa, (a, b) -> {
                if (r[a] != r[b]) return Integer.compare(r[a], r[b]);
                int ra = a + step < n ? r[a + step] : -1;
                int rb = b + step < n ? r[b + step] : -1;
                return Integer.compare(ra, rb);
            });
            tmp[sa[0]] = 0;
            for (int i = 1; i < n; i++) {
                tmp[sa[i]] = tmp[sa[i - 1]];
                int prev0 = r[sa[i - 1]], prev1 = sa[i - 1] + step < n ? r[sa[i - 1] + step] : -1;
                int cur0 = r[sa[i]], cur1 = sa[i] + step < n ? r[sa[i] + step] : -1;
                if (prev0 != cur0 || prev1 != cur1) tmp[sa[i]]++;
            }
            System.arraycopy(tmp, 0, rank, 0, n);
            if (rank[sa[n - 1]] == n - 1) break;
        }
        int[] result = new int[n];
        for (int i = 0; i < n; i++) result[i] = sa[i];
        return result;
    }
}

fun suffixArray(arr: IntArray): IntArray {
    val n = arr.size
    if (n == 0) return intArrayOf()
    val sa = Array(n) { it }
    var rank = arr.clone()
    val tmp = IntArray(n)
    var k = 1
    while (k < n) {
        val r = rank.clone()
        val step = k
        sa.sortWith(Comparator { a, b ->
            if (r[a] != r[b]) return@Comparator r[a] - r[b]
            val ra = if (a + step < n) r[a + step] else -1
            val rb = if (b + step < n) r[b + step] else -1
            ra - rb
        })
        tmp[sa[0]] = 0
        for (i in 1 until n) {
            tmp[sa[i]] = tmp[sa[i - 1]]
            val p0 = r[sa[i - 1]]; val c0 = r[sa[i]]
            val p1 = if (sa[i - 1] + step < n) r[sa[i - 1] + step] else -1
            val c1 = if (sa[i] + step < n) r[sa[i] + step] else -1
            if (p0 != c0 || p1 != c1) tmp[sa[i]]++
        }
        rank = tmp.clone()
        if (rank[sa[n - 1]] == n - 1) break
        k *= 2
    }
    return sa.map { it }.toIntArray()
}

def suffix_array(arr: list[int]) -> list[int]:
    n = len(arr)
    if n == 0:
        return []
    sa = list(range(n))
    rank = arr[:]
    tmp = [0] * n
    k = 1
    while k < n:
        def cmp_key(i):
            return (rank[i], rank[i + k] if i + k < n else -1)
        sa.sort(key=cmp_key)
        tmp[sa[0]] = 0
        for i in range(1, n):
            tmp[sa[i]] = tmp[sa[i - 1]]
            if cmp_key(sa[i]) != cmp_key(sa[i - 1]):
                tmp[sa[i]] += 1
        rank = tmp[:]
        if rank[sa[-1]] == n - 1:
            break
        k *= 2
    return sa

pub fn suffix_array(arr: &[i32]) -> Vec<i32> {
    let n = arr.len();
    if n == 0 {
        return vec![];
    }
    let mut sa: Vec<usize> = (0..n).collect();
    let mut rank: Vec<i64> = arr.iter().map(|&x| x as i64).collect();
    let mut tmp = vec![0i64; n];
    let mut k = 1;
    while k < n {
        let r = rank.clone();
        let step = k;
        sa.sort_by(|&a, &b| {
            let cmp1 = r[a].cmp(&r[b]);
            if cmp1 != std::cmp::Ordering::Equal {
                return cmp1;
            }
            let ra = if a + step < n { r[a + step] } else { -1 };
            let rb = if b + step < n { r[b + step] } else { -1 };
            ra.cmp(&rb)
        });
        tmp[sa[0]] = 0;
        for i in 1..n {
            tmp[sa[i]] = tmp[sa[i - 1]];
            let p0 = r[sa[i - 1]];
            let c0 = r[sa[i]];
            let p1 = if sa[i - 1] + step < n { r[sa[i - 1] + step] } else { -1 };
            let c1 = if sa[i] + step < n { r[sa[i] + step] } else { -1 };
            if p0 != c0 || p1 != c1 {
                tmp[sa[i]] += 1;
            }
        }
        rank = tmp.clone();
        if rank[sa[n - 1]] == (n as i64 - 1) {
            break;
        }
        k *= 2;
    }
    sa.iter().map(|&x| x as i32).collect()
}

object SuffixArray {
  def suffixArray(arr: Array[Int]): Array[Int] = {
    val n = arr.length
    if (n == 0) return Array.empty[Int]
    var sa = Array.tabulate(n)(identity)
    var rank = arr.clone()
    val tmp = new Array[Int](n)
    var k = 1
    while (k < n) {
      val r = rank.clone()
      val step = k
      sa = sa.sortWith((a, b) => {
        if (r(a) != r(b)) r(a) < r(b)
        else {
          val ra = if (a + step < n) r(a + step) else -1
          val rb = if (b + step < n) r(b + step) else -1
          ra < rb
        }
      })
      tmp(sa(0)) = 0
      for (i <- 1 until n) {
        tmp(sa(i)) = tmp(sa(i - 1))
        val p0 = r(sa(i - 1)); val c0 = r(sa(i))
        val p1 = if (sa(i - 1) + step < n) r(sa(i - 1) + step) else -1
        val c1 = if (sa(i) + step < n) r(sa(i) + step) else -1
        if (p0 != c0 || p1 != c1) tmp(sa(i)) += 1
      }
      rank = tmp.clone()
      if (rank(sa(n - 1)) == n - 1) return sa
      k *= 2
    }
    sa
  }
}

func suffixArray(_ arr: [Int]) -> [Int] {
    let n = arr.count
    if n == 0 { return [] }
    var sa = Array(0..<n)
    var rank = arr
    var tmp = [Int](repeating: 0, count: n)
    var k = 1
    while k < n {
        let r = rank
        let step = k
        sa.sort { a, b in
            if r[a] != r[b] { return r[a] < r[b] }
            let ra = a + step < n ? r[a + step] : -1
            let rb = b + step < n ? r[b + step] : -1
            return ra < rb
        }
        tmp[sa[0]] = 0
        for i in 1..<n {
            tmp[sa[i]] = tmp[sa[i - 1]]
            let p0 = r[sa[i - 1]], c0 = r[sa[i]]
            let p1 = sa[i - 1] + step < n ? r[sa[i - 1] + step] : -1
            let c1 = sa[i] + step < n ? r[sa[i] + step] : -1
            if p0 != c0 || p1 != c1 { tmp[sa[i]] += 1 }
        }
        rank = tmp
        if rank[sa[n - 1]] == n - 1 { break }
        k *= 2
    }
    return sa
}

export function suffixArray(arr: number[]): number[] {
    const n = arr.length;
    if (n === 0) return [];
    const sa = Array.from({ length: n }, (_, i) => i);
    let rank = [...arr];
    const tmp = new Array(n);
    for (let k = 1; k < n; k *= 2) {
        const r = [...rank];
        const step = k;
        sa.sort((a, b) => {
            if (r[a] !== r[b]) return r[a] - r[b];
            const ra = a + step < n ? r[a + step] : -1;
            const rb = b + step < n ? r[b + step] : -1;
            return ra - rb;
        });
        tmp[sa[0]] = 0;
        for (let i = 1; i < n; i++) {
            tmp[sa[i]] = tmp[sa[i - 1]];
            const p0 = r[sa[i - 1]], c0 = r[sa[i]];
            const p1 = sa[i - 1] + step < n ? r[sa[i - 1] + step] : -1;
            const c1 = sa[i] + step < n ? r[sa[i] + step] : -1;
            if (p0 !== c0 || p1 !== c1) tmp[sa[i]]++;
        }
        rank = [...tmp];
        if (rank[sa[n - 1]] === n - 1) break;
    }
    return sa;
}
